import {
  appendShoppingAuditEntry,
  flushShoppingAuditLog,
} from "./shopping-audit-log.mjs";
import { recordStagedCartItem } from "./shopping-active-carts-strip.mjs";

export const ASKET_RETAILER = "Asket";
export const ASKET_BASE_PRODUCT_URL = "https://www.asket.com/products";
export const ASKET_CART_URL = "https://www.asket.com/en-dk/cart";
export const ASKET_CART_STAGING_STATUSES = Object.freeze([
  "success",
  "out_of_stock",
  "login_expired",
  "error",
]);

export function createAsketProductUrl(productId, baseProductUrl = ASKET_BASE_PRODUCT_URL) {
  const normalizedProductId = normalizeNonEmptyString(productId, "productId");
  return `${baseProductUrl.replace(/\/+$/, "")}/${encodeURIComponent(normalizedProductId)}`;
}

export function createAsketCartStagingSelectors(size) {
  const normalizedSize = normalizeNonEmptyString(size, "size");
  const quotedSize = JSON.stringify(normalizedSize);

  return {
    loginExpired: [
      "form[action*='login']",
      "form[action*='account']",
      "text=/log in/i",
      "text=/sign in/i",
      "text=/session expired/i",
    ],
    outOfStock: [
      "text=/out of stock/i",
      "text=/sold out/i",
      "button:has-text(\"Sold out\")",
      "button:has-text(\"Out of stock\")",
    ],
    size: [
      `button:has-text(${quotedSize})`,
      `[data-testid*="size"] button:has-text(${quotedSize})`,
      `[aria-label=${quotedSize}]`,
      `input[name="size"][value=${quotedSize}]`,
    ],
    addToCart: [
      "button:has-text(\"Add to bag\")",
      "button:has-text(\"Add to cart\")",
      "button:has-text(\"Add\")",
      "[data-testid*='add-to-cart']",
      "[data-testid*='add-to-bag']",
    ],
  };
}

export async function stageAsketCartItem({
  page,
  productUrl,
  productId,
  size,
  auditLogPath,
  audit = appendShoppingAuditEntry,
  flushAudit = flushShoppingAuditLog,
  selectors = createAsketCartStagingSelectors(size),
  navigationWaitUntil = "domcontentloaded",
  activeCarts,
  now = () => new Date(),
} = {}) {
  validatePage(page);
  const normalizedSize = normalizeNonEmptyString(size, "size");
  const resolvedProductUrl =
    productUrl === undefined
      ? createAsketProductUrl(productId)
      : normalizeUrl(productUrl, "productUrl");

  const resultBase = {
    productUrl: resolvedProductUrl,
    retailer: ASKET_RETAILER,
    size: normalizedSize,
  };

  if (productId !== undefined) {
    resultBase.productId = normalizeNonEmptyString(productId, "productId");
  }

  let activeActionType = "cart_add";

  try {
    activeActionType = "page_read";
    auditStep(audit, auditLogPath, "page_read", "started");
    await page.goto(resolvedProductUrl, { waitUntil: navigationWaitUntil });

    if (await hasVisibleLocator(page, selectors.loginExpired)) {
      auditStep(audit, auditLogPath, "page_read", "failed");
      return {
        ...resultBase,
        reason: "Asket login session appears to be expired.",
        status: "login_expired",
      };
    }

    auditStep(audit, auditLogPath, "page_read", "succeeded");

    activeActionType = "size_select";
    auditStep(audit, auditLogPath, "size_select", "started");
    await clickFirstAvailableLocator(page, selectors.size, `size ${normalizedSize}`);
    auditStep(audit, auditLogPath, "size_select", "succeeded");

    activeActionType = "cart_add";
    auditStep(audit, auditLogPath, "cart_add", "started");
    if (await hasVisibleLocator(page, selectors.outOfStock)) {
      auditStep(audit, auditLogPath, "cart_add", "failed");
      return {
        ...resultBase,
        reason: "Selected Asket size is out of stock.",
        status: "out_of_stock",
      };
    }

    const addToCartLocator = await findFirstVisibleLocator(page, selectors.addToCart);
    if (!addToCartLocator) {
      throw new Error("Could not find an Asket add-to-cart button.");
    }
    if (!(await locatorIsEnabled(addToCartLocator))) {
      auditStep(audit, auditLogPath, "cart_add", "failed");
      return {
        ...resultBase,
        reason: "Selected Asket size is out of stock.",
        status: "out_of_stock",
      };
    }

    await addToCartLocator.click();

    if (await hasVisibleLocator(page, selectors.loginExpired)) {
      auditStep(audit, auditLogPath, "cart_add", "failed");
      return {
        ...resultBase,
        reason: "Asket login session expired before cart add completed.",
        status: "login_expired",
      };
    }

    auditStep(audit, auditLogPath, "cart_add", "succeeded");
    const activeCartRow = activeCarts
      ? recordStagedCartItem(activeCarts, {
          cartUrl: ASKET_CART_URL,
          retailer: ASKET_RETAILER,
          stagedAt: now(),
        })
      : undefined;
    return {
      ...resultBase,
      ...(activeCartRow ? { activeCartRow } : {}),
      status: "success",
    };
  } catch (err) {
    auditStep(audit, auditLogPath, activeActionType, "failed");
    return {
      ...resultBase,
      error: err instanceof Error ? err.message : String(err),
      status: "error",
    };
  } finally {
    if (typeof flushAudit === "function") {
      await flushAudit();
    }
  }
}

function auditStep(audit, auditLogPath, actionType, status) {
  if (typeof audit !== "function") {
    return;
  }

  audit(
    {
      actionType,
      retailer: ASKET_RETAILER,
      status,
    },
    auditLogPath,
  );
}

async function clickFirstAvailableLocator(page, selectors, description) {
  for (const selector of normalizeSelectors(selectors)) {
    const locator = firstLocator(page, selector);
    if ((await locatorHasMatches(locator)) && (await locatorIsVisible(locator))) {
      if (!(await locatorIsEnabled(locator))) {
        continue;
      }
      await locator.click();
      return selector;
    }
  }

  throw new Error(`Could not find an enabled Asket ${description}.`);
}

async function hasVisibleLocator(page, selectors) {
  return Boolean(await findFirstVisibleLocator(page, selectors));
}

async function findFirstVisibleLocator(page, selectors) {
  for (const selector of normalizeSelectors(selectors)) {
    const locator = firstLocator(page, selector);
    if ((await locatorHasMatches(locator)) && (await locatorIsVisible(locator))) {
      return locator;
    }
  }
  return undefined;
}

function firstLocator(page, selector) {
  const locator = page.locator(selector);
  return locator.first?.() ?? locator;
}

async function locatorHasMatches(locator) {
  if (typeof locator.count === "function") {
    return (await locator.count()) > 0;
  }
  return true;
}

async function locatorIsVisible(locator) {
  if (typeof locator.isVisible === "function") {
    return locator.isVisible();
  }
  return true;
}

async function locatorIsEnabled(locator) {
  if (typeof locator.isEnabled === "function") {
    return locator.isEnabled();
  }
  return true;
}

function validatePage(page) {
  if (!page || typeof page.goto !== "function" || typeof page.locator !== "function") {
    throw new TypeError("page must provide Playwright-compatible goto and locator methods.");
  }
}

function normalizeSelectors(selectors) {
  if (!Array.isArray(selectors) || selectors.length === 0) {
    throw new TypeError("selectors must be a non-empty array.");
  }
  return selectors.map((selector) => normalizeNonEmptyString(selector, "selector"));
}

function normalizeNonEmptyString(value, field) {
  if (typeof value !== "string" || !value.trim()) {
    throw new TypeError(`${field} must be a non-empty string.`);
  }
  return value.trim();
}

function normalizeUrl(value, field) {
  const normalized = normalizeNonEmptyString(value, field);
  try {
    return new URL(normalized).toString();
  } catch {
    throw new TypeError(`${field} must be a valid URL.`);
  }
}

import { ASKET_RETAILER_IDENTIFIER } from "./asket-login-flow.mjs";
import { VisibleAutomationBrowserRun } from "./automation-browser.mjs";
import { ensureRetailerBrowserProfile } from "./shopping-browser-profiles.mjs";
import { SHOPPING_MEMORY_TAG } from "./shopping-profile.mjs";

export { ASKET_RETAILER_IDENTIFIER };
export const ASKET_SEARCH_URL_BASE = "https://www.asket.com/en-dk/search";
export const ASKET_PRODUCT_SEARCH_MAX_CANDIDATES = 3;
const MEMORY_MATCH_STOP_WORDS = Object.freeze([
  "asket",
  "because",
  "black",
  "blue",
  "collar",
  "green",
  "returned",
  "shirt",
  "shirts",
  "size",
  "white",
]);

export async function searchAsketProducts({
  intent,
  products,
  searchProducts,
  browserRun,
  launcher,
  windowManager,
  chat,
  profilesRoot,
  searchUrlBase = ASKET_SEARCH_URL_BASE,
  maxCandidates = ASKET_PRODUCT_SEARCH_MAX_CANDIDATES,
  memories = [],
} = {}) {
  const normalizedIntent = normalizeAsketProductIntent(intent);
  const normalizedMaxCandidates = normalizeMaxCandidates(maxCandidates);
  const rankingMemories = normalizeRankingMemories(memories);
  const searchUrl = createAsketSearchUrl(normalizedIntent, searchUrlBase);
  const rawProducts =
    products ??
    (await fetchAsketProducts({
      browserRun,
      chat,
      intent: normalizedIntent,
      launcher,
      profilesRoot,
      searchProducts,
      searchUrl,
      windowManager,
    }));

  if (!Array.isArray(rawProducts)) {
    throw new TypeError("Asket product search adapter must return an array.");
  }

  return rankAsketProducts(rawProducts, normalizedIntent, rankingMemories)
    .slice(0, normalizedMaxCandidates)
    .map(({ candidate }) => candidate);
}

export function createAsketSearchUrl(intent, searchUrlBase = ASKET_SEARCH_URL_BASE) {
  const normalizedIntent = normalizeAsketProductIntent(intent);
  const url = new URL(searchUrlBase);
  url.searchParams.set("q", buildAsketSearchQuery(normalizedIntent));
  return url.toString();
}

export function normalizeAsketProductIntent(intent) {
  if (!intent || typeof intent !== "object" || Array.isArray(intent)) {
    throw new TypeError("Asket product intent must be an object.");
  }

  const garmentClass = normalizeString(intent.garmentClass, "garmentClass");
  const size = normalizeString(intent.size, "size");
  const colorKeywords = normalizeColorKeywords(intent.colorKeywords ?? intent.colors);
  const priceCeiling = normalizePrice(intent.priceCeiling, "priceCeiling");

  return {
    garmentClass,
    size,
    colorKeywords,
    priceCeiling,
  };
}

function buildAsketSearchQuery(intent) {
  return [intent.garmentClass, ...intent.colorKeywords].join(" ");
}

async function fetchAsketProducts({
  browserRun,
  chat,
  intent,
  launcher,
  profilesRoot,
  searchProducts,
  searchUrl,
  windowManager,
}) {
  if (typeof searchProducts !== "function") {
    throw new TypeError("searchProducts must be a function when products are not provided.");
  }

  if (!browserRun && !launcher) {
    return searchProducts({
      intent,
      retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
      searchUrl,
    });
  }

  const profile = await ensureRetailerBrowserProfile(ASKET_RETAILER_IDENTIFIER, profilesRoot);
  const run =
    browserRun ??
    new VisibleAutomationBrowserRun({
      chat,
      launcher,
      windowManager,
    });

  await run.startStagingRun({
    retailer: ASKET_RETAILER_IDENTIFIER,
    startUrl: searchUrl,
    userDataDir: profile.userDataDir,
  });

  const session = run.requireCurrentRun().session;
  await openSearchPage(session, searchUrl);

  try {
    const result = await searchProducts({
      intent,
      profile,
      retailerIdentifier: ASKET_RETAILER_IDENTIFIER,
      searchUrl,
      session,
    });
    await run.completeSuccessfully();
    return result;
  } catch (err) {
    if (typeof run.completeSuccessfully === "function") {
      await run.completeSuccessfully();
    }
    throw err;
  }
}

function rankAsketProducts(products, intent, memories = []) {
  return products
    .map((product, index) => normalizeAsketProductCandidate(product, intent, index))
    .filter(({ candidate }) => candidate.price.amount <= intent.priceCeiling.amount)
    .filter(({ candidate }) => candidate.price.currency === intent.priceCeiling.currency)
    .filter(({ searchableText, candidate }) =>
      matchesGarment(searchableText, intent.garmentClass, candidate.title),
    )
    .filter(({ searchableText, candidate }) =>
      matchesColor(searchableText, candidate.color, intent.colorKeywords),
    )
    .filter(({ candidate, availableSizes }) =>
      matchesSize(candidate.size, availableSizes, intent.size),
    )
    .map((entry) => ({
      ...entry,
      score: scoreCandidate(entry, intent) - shoppingMemoryPenalty(entry, memories),
      candidate: {
        ...entry.candidate,
        reasoning: createReasoning(entry, intent, memories),
      },
    }))
    .sort((left, right) => right.score - left.score || left.index - right.index);
}

function normalizeAsketProductCandidate(product, intent, index) {
  if (!product || typeof product !== "object" || Array.isArray(product)) {
    throw new TypeError("Asket product candidates must be objects.");
  }

  const productUrl = normalizeUrl(
    product.productUrl ?? product.url,
    `products[${index}].productUrl`,
  );
  const imageUrl = normalizeUrl(product.imageUrl ?? product.image, `products[${index}].imageUrl`);
  const title = normalizeString(product.title, `products[${index}].title`);
  const color = normalizeString(product.color, `products[${index}].color`);
  const price = normalizePrice(product.price, `products[${index}].price`);
  const availableSizes = normalizeOptionalStringArray(product.availableSizes ?? product.sizes);
  const size = normalizeCandidateSize(product.size, availableSizes, intent.size);
  const brand =
    product.brand === undefined
      ? ASKET_RETAILER_IDENTIFIER
      : normalizeString(product.brand, `products[${index}].brand`);
  const tags = normalizeOptionalStringArray(product.tags);
  const category =
    product.category === undefined
      ? ""
      : normalizeString(product.category, `products[${index}].category`);
  const searchableText = normalizeSearchText(
    [title, color, category, ...tags, ...availableSizes].join(" "),
  );

  return {
    availableSizes,
    candidate: {
      productUrl,
      imageUrl,
      brand,
      title,
      size,
      color,
      price,
      reasoning: "",
    },
    index,
    searchableText,
  };
}

function normalizeCandidateSize(size, availableSizes, requestedSize) {
  if (size !== undefined) {
    return normalizeString(size, "size");
  }
  if (availableSizes.some((candidateSize) => sameSize(candidateSize, requestedSize))) {
    return requestedSize;
  }
  return availableSizes[0] ?? requestedSize;
}

function scoreCandidate({ candidate, searchableText, availableSizes }, intent) {
  let score = 0;
  const garmentText = normalizeSearchText(intent.garmentClass);
  const titleText = normalizeSearchText(candidate.title);
  if (hasSearchTerm(titleText, garmentText)) {
    score += 40;
  } else if (hasSearchTerm(searchableText, garmentText)) {
    score += 25;
  }

  if (sameSize(candidate.size, intent.size)) {
    score += 20;
  } else if (availableSizes.some((size) => sameSize(size, intent.size))) {
    score += 16;
  }

  score += colorMatchCount(`${candidate.color} ${candidate.title}`, intent.colorKeywords) * 15;
  score += colorMatchCount(searchableText, intent.colorKeywords) * 5;
  if (intent.priceCeiling.amount > 0) {
    score += Math.max(0, 10 - (candidate.price.amount / intent.priceCeiling.amount) * 10);
  }
  return score;
}

function createReasoning(entry, intent, memories) {
  const { candidate } = entry;
  const currency = candidate.price.currency;
  const memoryNote =
    shoppingMemoryPenalty(entry, memories) > 0 ? " De-prioritized by Shopping memory." : "";
  return `Matches ${intent.garmentClass}, ${intent.colorKeywords.join("/")}, size ${candidate.size} under ${currency} ${intent.priceCeiling.amount}.${memoryNote}`;
}

