async function extractZalandoProductCards(session) {
  if (session && typeof session.extractProducts === "function") {
    return session.extractProducts({ retailerIdentifier: ZALANDO_RETAILER_IDENTIFIER });
  }
  if (session && typeof session.evaluate === "function") {
    return session.evaluate(() =>
      Array.from(
        document.querySelectorAll("article, [data-testid*='product'], [class*='product-card']"),
      )
        .map((card) => {
          const link = card.querySelector("a[href]");
          const image = card.querySelector("img");
          const text = card.textContent ?? "";
          return {
            productUrl: link?.href,
            imageUrl: image?.currentSrc || image?.src,
            title: image?.alt || text.split("\n").map((part) => part.trim()).find(Boolean),
            color: text,
            priceText: text,
            tags: [text],
          };
        })
        .filter((product) => product.productUrl && product.title),
    );
  }
  throw new TypeError("session must provide extractProducts or evaluate for Zalando.lv search.");
}

