export async function searchHmProducts({
  intent,
  products,
  searchProducts,
  browserRun,
  launcher,
  windowManager,
  chat,
  profilesRoot,
  searchUrlBase = HM_SEARCH_URL_BASE,
  maxCandidates = HM_PRODUCT_SEARCH_MAX_CANDIDATES,
  memories = [],
} = {}) {
  const normalizedIntent = normalizeHmProductIntent(intent);
  const normalizedMaxCandidates = normalizeMaxCandidates(maxCandidates);
  const rankingMemories = normalizeRankingMemories(memories);
  const searchUrl = createHmSearchUrl(normalizedIntent, searchUrlBase);
  const rawProducts =
    products ??
    (await fetchHmProducts({
      browserRun,
      chat,
      intent: normalizedIntent,
      launcher,
      profilesRoot,
      searchProducts,
      searchUrl,
      windowManager,
    }));

  if (!Array.isArray(rawProducts)) {
    throw new TypeError("H&M.lv product search adapter must return an array.");
  }

  return rankHmProducts(rawProducts, normalizedIntent, rankingMemories)
    .slice(0, normalizedMaxCandidates)
    .map(({ candidate }) => candidate);
}

export function createHmSearchUrl(intent, searchUrlBase = HM_SEARCH_URL_BASE) {
  const normalizedIntent = normalizeHmProductIntent(intent);
  const url = new URL(searchUrlBase);
  url.searchParams.set("q", buildHmSearchQuery(normalizedIntent));
  return url.toString();
}

export function normalizeHmProductIntent(intent) {
  if (!intent || typeof intent !== "object" || Array.isArray(intent)) {
    throw new TypeError("H&M.lv product intent must be an object.");
  }

  return {
    garmentClass: normalizeString(intent.garmentClass, "garmentClass"),
    size: normalizeString(intent.size, "size"),
    colorKeywords: normalizeColorKeywords(intent.colorKeywords ?? intent.colors),
    priceCeiling: normalizePrice(intent.priceCeiling, "priceCeiling"),
  };
}

function buildHmSearchQuery(intent) {
  return [intent.garmentClass, ...intent.colorKeywords].join(" ");
}

async function fetchHmProducts({
